  ('fire-eq-eng-moex-00845', 'fire-eq-eng', 'fire-eq-eng-moex-102-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依消防幫浦加壓送水裝置等及配管摩擦損失計算基準，幫浦之性能應符合下列何項規定？', '["幫浦所標示之額定出水量，在其性能曲線上之全揚程必須達到額定揚程之100%至120%之間", "幫浦之出水量在額定出水量140%時，其全揚程應達到額定出水量性能曲線上全揚程之65%以上", "全閉揚程應為性能曲線上全揚程之150%以下", "在額定出水量150%時，其軸動力不得超過馬達額定輸出馬力之110%"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:18+00:00", "source_pdf_sha1": "8aecb6ec0845", "answer_pdf_sha1": "755533a816ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "102070", "c": "901", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規", "year": "102", "exam_name": "102年專技驗船師引水人、第一次食品技師考試消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
